import React from 'react'
import c from './workers.module.scss'
import { periods } from '../../utils'
import { Icons } from '../../assets/icons'
import { API } from '../../api'
import { Components } from '..'

const ClientsTable = () => {
  const [ month, setMonth ] = React.useState()
  const [ clients, setClients ] = React.useState(null)
  const [ active, setActive ] = React.useState(false)
  const months = [
    "Январь", "Февраль", "Март", "Апрель", "Май", "Июнь",
      "Июль", "Август", "Сентябрь", "Октябрь", "Ноябрь", "Декабрь"
  ];

  React.useEffect(() => {
    const date = new Date()
    const month = date.toLocaleString('ru', { month: 'long' })
    setMonth(month.slice(0, 1).toUpperCase() + month.slice(1))

    API.getClients()
      .then(res => {
        const data = Object.keys(res.data).map(key => ({
          ...res.data[key],
          id: key,
        }))
        console.log(data)
    })
  }, [])


  const filteredClients = React.useMemo(() => {
    if (!clients) return [];

    // Показать всех клиентов, если выбрана 5-я неделя (условно "весь месяц")
    if (selectedWeek === 5) {
      return clients.filter(client => {
        if (!client.date) return false;

        const [day, month, year] = client.date.split('.').map(Number);
        return (month - 1) === currentMonth && (2000 + year) === currentYear;
      });
    }

    // Если недель меньше, чем выбранная неделя — просто вернуть всех
    if (!weeks[selectedWeek]) return clients;

    const [start, end] = [weeks[selectedWeek][0], weeks[selectedWeek].slice(-1)[0]];

    return clients.filter(client => {
      if (!client.date) return false;

      const [day, month, year] = client.date.split('.').map(Number);
      const clientDate = new Date(2000 + year, month - 1, day);

      return clientDate >= start && clientDate <= end;
    });
  }, [clients, selectedWeek]);


  return (
    <div className={c.workers}>
      <div className={c.title}>
        <div className={c.left}>
          <button onClick={() => setActive(true)}>
            + Добавить
          </button>

          <div className={c.search}>
            <img src={Icons.search} alt="search" />
            <input
              type="text"
              placeholder='Найти клиентов'
            />
          </div>
        </div>
        <div className={c.right}>
          <div className={c.date}>
            <span>
              {month}
            </span>
            <button>
              Выбрать месяц
            </button>
          </div>
          <span className={c.line}></span>
          <div className={c.periods}>
            {
              periods.map(item => (
                <button key={item.id} className={selectedWeek === item.id ? c.active : ''} onClick={() => setSelectedWeek(item.id)}>
                  {item.title}
                </button>
              ))
            }
          </div>
        </div>
      </div>
      <div className={c.table}>
        <table>
          <thead>
            <tr>
              <th>
                <img src={Icons.edit} alt="edit" />
              </th>
              <th>Время</th>
              <th>Ф.И.О клиента</th>
              <th>Телефон</th>
              <th className={c.services}>Процедуры</th>
              <th>Сотрудник</th>
              <th>Прайс по итогу</th>
            </tr>
          </thead>
          <tbody>
            {
              filteredClients?.length !== 0 ?
              filteredClients.map(item => (
                <tr key={item.id}>
                  <td>
                    <img src={Icons.edit} alt="edit" />
                  </td>
                  <td>
                    <div className={c.date}>
                      {item.appointment_day} {months[item.appointment_month - 1]}
                    </div>
                    <div className={c.date}>
                      {item.appointment_time.slice(0, 5)}
                    </div>
                  </td>
                  <td>{item.full_name}</td>
                  <td>{item.phone_number}</td>
                  <td className={c.services}>
                    {item?.services.map(value => (
                      <div key={value.id} className={c.service}>
                        {value.name}
                      </div>
                    ))}
                  </td>
                  <td>
                    <div className={c.worker}>
                      {item.worker.name}
                    </div>
                  </td>
                  <td>{Array.isArray(item?.services)
                  ? item.services.reduce((sum, obj) => sum + Number(obj.price), 0)
                  : 0}
                </td>
                </tr>
              )) :
              <tr>
                  <td>
                    <img src={Icons.edit} alt="edit" />
                  </td>
                  <td>
                    Клиентов нет
                  </td>
                  <td></td>
                  <td></td>
                  <td className={c.services}>

                  </td>
                  <td>

                  </td>
                  <td>
                  </td>
              </tr>
            }
          </tbody>
        </table>
      </div>

      {
        active ?
        <Components.AddClient setActive={setActive} /> :
        null
      }
    </div>
  )
}

export default ClientsTable
